SELECT count(*) FROM aka_name, name, cast_info, char_name, title, movie_keyword, role_type, keyword, movie_info WHERE aka_name.person_id = name.id AND cast_info.person_id = name.id AND cast_info.person_role_id = char_name.id AND cast_info.movie_id = title.id AND movie_keyword.movie_id = title.id AND cast_info.role_id = role_type.id AND movie_keyword.keyword_id = keyword.id AND movie_info.movie_id = title.id;